    return StreamingResponse(generator(), media_type="application/octet-stream")

import pathlib

@app.post("/upload/")
async def upload(file: UploadFile = File(...)):
    # Sanitize filename
    safe_name = pathlib.Path(file.filename).name  # Strips path traversal
    if ".." in safe_name or "/" in safe_name:
        raise HTTPException(400, "Invalid filename")

    # Limit size
    content = await file.read(10 * 1024 * 1024)  # Max 10MB
    if len(content) == 10 * 1024 * 1024:
        raise HTTPException(413, "File too large")

    return {"filename": safe_name, "size": len(content)}
